import logging
import json
import hmac
import hashlib
import azure.functions as func
from typing import Dict, Any
from urllib.parse import urlparse

# Configuration
ALLOWED_PROVIDERS = ['stripe', 'paypal', 'square']
PAYMENT_PROVIDER_WEBHOOK_SECRET = 'YOUR_WEBHOOK_SECRET_HERE'  # Store in Azure Key Vault
VALID_DOMAINS = ['https://api.stripe.com', 'https://api.paypal.com']

def validate_payment_provider(provider: str) -> bool:
    """Validate payment provider against allowed list"""
    return provider.lower() in ALLOWED_PROVIDERS

def validate_webhook_signature(payload: bytes, signature: str, secret: str) -> bool:
    """Validate webhook signature using HMAC"""
    expected_signature = 'v1=' + hmac.new(
        secret.encode('utf-8'),
        payload,
        hashlib.sha256
    ).hexdigest()
    
    return hmac.compare_digest(signature, expected_signature)

def validate_request_origin(url: str) -> bool:
    """Validate that request comes from a known domain"""
    try:
        parsed_url = urlparse(url)
        return parsed_url.scheme == 'https' and parsed_url.netloc in [domain.split('//')[1] for domain in VALID_DOMAINS]
    except Exception:
        return False

def process_payment_notification(notification_data: Dict[str, Any]) -> Dict[str, Any]:
    """Process payment notification data"""
    try:
        # Validate required fields
        required_fields = ['event_type', 'payment_id', 'amount', 'currency']
        for field in required_fields:
            if field not in notification_data:
                raise ValueError(f"Missing required field: {field}")
        
        # Validate payment provider
        provider = notification_data.get('provider')
        if not validate_payment_provider(provider):
            raise ValueError(f"Invalid payment provider: {provider}")
        
        # Process payment logic here
        result = {
            'status': 'success',
            'payment_id': notification_data['payment_id'],
            'processed_at': notification_data.get('timestamp', ''),
            'provider': provider
        }
        
        logging.info(f"Processed payment notification: {result}")
        return result
        
    except Exception as e:
        logging.error(f"Error processing payment notification: {str(e)}")
        raise

def main(req: func.HttpRequest) -> func.HttpResponse:
    """HTTP trigger function for payment webhook"""
    logging.info('Payment webhook function processed a request.')
    
    try:
        # Validate HTTP method
        if req.method != 'POST':
            return func.HttpResponse(
                'Method not allowed',
                status_code=405
            )
        
        # Get headers
        signature = req.headers.get('Stripe-Signature') or req.headers.get('Paypal-Webhook-Signature')
        provider = req.headers.get('X-Payment-Provider')
        
        # Validate provider header
        if not provider:
            return func.HttpResponse(
                'Missing payment provider header',
                status_code=400
            )
        
        # Validate request origin
        if not validate_request_origin(req.url):
            return func.HttpResponse(
                'Invalid request origin',
                status_code=403
            )
        
        # Get request body
        try:
            req_body = req.get_json()
        except ValueError:
            return func.HttpResponse(
                'Invalid JSON in request body',
                status_code=400
            )
        
        # Validate webhook signature if available
        if signature:
            payload = req.get_body()
            if not validate_webhook_signature(payload, signature, PAYMENT_PROVIDER_WEBHOOK_SECRET):
                return func.HttpResponse(
                    'Invalid webhook signature',
                    status_code=401
                )
        
        # Process notification
        result = process_payment_notification(req_body)
        
        return func.HttpResponse(
            json.dumps(result),
            status_code=200,
            mimetype='application/json'
        )
        
    except Exception as e:
        logging.error(f"Unexpected error in webhook function: {str(e)}")
        return func.HttpResponse(
            'Internal server error',
            status_code=500
        )